/*
3. 无重复字符的最长子串
中等
相关标签
premium lock icon
相关企业
提示
给定一个字符串 s ，请你找出其中不含有重复字符的 最长 子串 的长度。



示例 1:

输入: s = "abcabcbb"
输出: 3
解释: 因为无重复字符的最长子串是 "abc"，所以其长度为 3。注意 "bca" 和 "cab" 也是正确答案。
示例 2:

输入: s = "bbbbb"
输出: 1
解释: 因为无重复字符的最长子串是 "b"，所以其长度为 1。
示例 3:

输入: s = "pwwkew"
输出: 3
解释: 因为无重复字符的最长子串是 "wke"，所以其长度为 3。
     请注意，你的答案必须是 子串 的长度，"pwke" 是一个子序列，不是子串。


提示：

0 <= s.length <= 5 * 104
s 由英文字母、数字、符号和空格组成
*/

#include <algorithm>
#include <iostream>
#include <string>
#include <vector>

using namespace std;

class Solution {
 public:
  int lengthOfLongestSubstring(string s) {
    int num = 0;
    int max = 0;
    std::vector<char> cv;

    decltype(cv.begin()) iter;
    cv.reserve(5 * 10e4);
    for (auto i = s.begin(); i != s.end(); i++) {
      if (cv.empty()) {
        cv.push_back(*i);
        num++;
        iter = cv.begin();
        continue;
      }
      if (auto it = find(iter, cv.end(), *i); it == cv.end()) {
        cv.push_back(*i);
        num++;
      } else {
        cv.push_back(*i);
        if (num > max) max = num;
        while (true) {
          iter++;
          if (iter != it + 1) {
            num--;
          } else {
            break;
          }
        }
      }
    }

    if (num > max) max = num;

    return max;
  }
};


